 1→import type { Meta, StoryObj } from '@storybook/react-vite';
 2→import { expect } from 'storybook/test';
 3→import { HeatmapChart } from './charts';
 4→import { CanvasRenderer } from 'echarts/renderers';
 5→import { GridComponent } from 'echarts/components';
 6→import { VisualMap } from './components';
 7→
 8→const heatmapData: [number, number, number][] = [];
 9→for (let i = 0; i < 5; i++) {
10→  for (let j = 0; j < 7; j++) {
11→    heatmapData.push([i, j, Math.round(Math.random() * 100)]);
12→  }
13→}
14→
15→const meta = {
16→  component: HeatmapChart,
17→  tags: ['ai-generated', 'needs-work'],
18→  args: {
19→    use: [CanvasRenderer, GridComponent],
20→    style: { width: 600, height: 400 },
21→    xAxis: { type: 'category' as const, data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'] },
22→    yAxis: { type: 'category' as const, data: ['Morning', 'Mid-Morning', 'Noon', 'Afternoon', 'Evening', 'Night', 'Late Night'] },
23→    series: [
24→      {
25→        type: 'heatmap' as const,
26→        data: heatmapData,
27→        label: { show: true },
28→      },
29→    ],
30→  },
31→} satisfies Meta<any>;
32→
33→export default meta;
34→type Story = StoryObj<typeof meta>;
35→
36→export const Default: Story = {
37→  render: (args) => (
38→    <HeatmapChart {...args}>
39→      <VisualMap visualMap={{ min: 0, max: 100, calculable: true }} />
40→    </HeatmapChart>
41→  ),
42→  play: async ({ canvasElement }) => {
43→    const canvas = canvasElement.querySelector('canvas');
44→    await expect(canvas).not.toBeNull();
45→  },
46→};
47→
48→export const WithVisualMap: Story = {
49→  render: (args) => (
50→    <HeatmapChart {...args}>
51→      <VisualMap visualMap={{ min: 0, max: 100, calculable: true, orient: 'horizontal', left: 'center', bottom: '5%' }} />
52→    </HeatmapChart>
53→  ),
54→};
